import numpy as np
from typing import List, Dict, Tuple
from dataclasses import dataclass

@dataclass
class MomentumSignal:
    symbol: str
    score: float
    direction: str
    confidence: float

class QuantumMomentumStrategy:
    def __init__(self, lookback_periods: List[int] = [5, 10, 20]):
        self.lookback_periods = lookback_periods

    def calculate_momentum(self, prices: np.ndarray, period: int) -> float:
        if len(prices) <= period:
            return 0.0
        return (prices[-1] / prices[-period]) - 1

    def calculate_consistency(self, momentums: Dict[int, float]) -> float:
        if not momentums:
            return 0.0
        signs = [np.sign(m) for m in momentums.values() if m != 0]
        if not signs:
            return 0.0
        return abs(sum(signs)) / len(signs)

    def generate_signal(self, symbol: str, 
                        prices: np.ndarray) -> MomentumSignal:
        if len(prices) < max(self.lookback_periods):
            return MomentumSignal(symbol, 0.0, "neutral", 0.0)

        # Calculate momentum for each period
        momentums = {
            period: self.calculate_momentum(prices, period)
            for period in self.lookback_periods
        }

        # Weighted average momentum
        weights = {5: 0.5, 10: 0.3, 20: 0.2}
        weighted_mom = sum(
            momentums.get(p, 0) * weights.get(p, 0.33)
            for p in self.lookback_periods
        )

        # Consistency score
        consistency = self.calculate_consistency(momentums)

        # Volatility adjustment
        returns = np.diff(np.log(prices[-20:]))
        volatility = np.std(returns)
        vol_adjustment = 1 / (1 + volatility * 10)

        # Final score
        score = weighted_mom * consistency * vol_adjustment

        # Direction and confidence
        direction = "long" if score > 0 else "short" if score < 0 else "neutral"
        confidence = consistency * (1 - min(volatility * 20, 0.5))

        return MomentumSignal(symbol, score, direction, confidence)

    def rank_signals(self, 
                     signals: List[MomentumSignal]) -> List[MomentumSignal]:
        return sorted(
            signals,
            key=lambda s: abs(s.score) * s.confidence,
            reverse=True
        )

# Test
np.random.seed(42)

stocks = {}
for symbol in ["AAPL", "GOOGL", "MSFT", "AMZN"]:
    drift = np.random.uniform(-0.002, 0.004)
    prices = 100 * np.exp(np.cumsum(np.random.normal(drift, 0.02, 60)))
    stocks[symbol] = prices

strategy = QuantumMomentumStrategy()

signals = []
for symbol, prices in stocks.items():
    signal = strategy.generate_signal(symbol, prices)
    signals.append(signal)

ranked = strategy.rank_signals(signals)

print("Momentum Signals (Ranked):")
for sig in ranked:
    print(f"  {sig.symbol}: {sig.direction}, Score={sig.score:.4f}, "
          f"Confidence={sig.confidence:.2f}")
